<#
.SYNOPSIS
  一鍵掃描並將文字檔轉為 UTF-8 (no BOM)，安裝 dev 依賴，執行 pre-commit，commit 並 push。

.PARAMETER DryRun
  若指定，僅顯示將要做的動作，不會修改檔案或執行 git commit/push。

.EXAMPLE
  .\fix_and_commit.ps1
  .\fix_and_commit.ps1 -DryRun
#>

param(
  [switch]
)

function Write-Info() { Write-Host "[INFO] " -ForegroundColor Cyan }
function Write-Warn() { Write-Host "[WARN] " -ForegroundColor Yellow }
function Write-Err()  { Write-Host "[ERROR] " -ForegroundColor Red }

# 1. 先檢查 git 狀態
Write-Info "檢查 git 工作目錄狀態..."
 = git status --porcelain
if () {
  Write-Warn "工作目錄有未提交的變更："
  Write-Host 
  Write-Warn "建議先 stash 或切換到新分支再執行腳本，或使用 DryRun 檢查。"
}

# 2. 掃描檔案並轉碼（只處理文字檔）
Write-Info "掃描專案檔案（尋找 UTF-16 或含 UTF-8 BOM 的檔案）..."
 = Get-Location
.gitignore .pre-commit-config.yaml pyproject.toml pyproject.toml.bak pyproject.toml.restored = Get-ChildItem -Recurse -File -ErrorAction SilentlyContinue | Where-Object {
  .FullName -notmatch '\\.git\\' -and .Length -gt 0
}

 = @()

