# 3. 安裝開發依賴（若有 requirements-dev.txt）
 = Join-Path  'requirements-dev.txt'
if (Test-Path ) {
  Write-Info "安裝開發依賴：requirements-dev.txt"
  if () {
    Write-Warn "DryRun 模式：不會實際安裝套件。"
  } else {
    python -m pip install --upgrade pip
    python -m pip install -r 
  }
} else {
  Write-Warn "找不到 requirements-dev.txt，請確認是否存在於專案根目錄。"
}

# 4. 執行 pre-commit
Write-Info "執行 pre-commit run --all-files"
if () {
  Write-Warn "DryRun 模式：不會執行 pre-commit。"
} else {
  pre-commit run --all-files
  if (0 -ne 0) {
    Write-Err "pre-commit 有錯誤，請先修正再 commit。腳本停止。"
    exit 1
  }
}

# 5. git add / commit / push
Write-Info "將變更加入暫存並提交到遠端"
if () {
  Write-Warn "DryRun 模式：不會執行 git commit 或 git push。"
} else {
  git add -A
   = git status --porcelain
  if (-not ) {
    Write-Info "沒有變更需要提交。"
  } else {
    git commit -m "Normalize encodings, run pre-commit and apply fixes"
    if (0 -ne 0) {
      Write-Err "git commit 失敗，請檢查錯誤訊息。"
      exit 1
    }
    git push
    if (0 -ne 0) {
      Write-Err "git push 失敗，請檢查遠端權限或網路。"
      exit 1
    }
    Write-Info "已成功 push 到遠端。"
  }
}

Write-Info "腳本執行完成。"